-- ── Aserto ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Aserto was a developer-focused authorization platform for building fine-grained permissions such as RBAC, ABAC, and ReBAC into applications using policy-as-code and Open Policy Agent, before the company wound down its commercial SaaS in 2025.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Redmond, Washington, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Aserto Review 2026: Authorization Platform Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$Aserto built a developer authorization platform on Open Policy Agent with policy-as-code and fine-grained permissions. See what it offered and its current status.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Aserto was a developer-focused authorization platform founded in 2020 in Redmond, Washington, by Omri Gazitt and Gert Drapers, two veteran developer-tools executives who had previously worked together at Microsoft, HP Cloud, Splunk, Puppet, and other companies. In June 2021, Aserto announced a $5.1 million seed round led by Costanoa Ventures, with participation from Heavybit Industries and angel investors including former Snowflake CEO Bob Muglia, Netlify co-founder Mathias Biilmann, and GitHub co-founder Tom Preston-Werner. The company's product let application developers add enterprise-grade, fine-grained authorization to their software using policy-as-code, supporting multiple access-control models in one platform: role-based access control (RBAC), attribute-based access control (ABAC), policy-based access control (PBAC), and relationship-based access control (ReBAC). At the core of the platform was Topaz, an open-source authorizer built on Open Policy Agent (OPA), the widely adopted CNCF policy engine. Aserto's commercial offering historically had four tiers: a free Starter plan for personal projects and evaluation, an Essentials tier priced at $0.20 per user per month with unlimited policy repositories, and custom-priced Pro and Enterprise tiers aimed at SaaS vendors and larger organizations needing identity provider integrations (Okta, Azure AD), longer decision-log retention, VPC deployment, and dedicated support. In 2025, however, Aserto's founders announced they were sunsetting the company's hosted SaaS control plane by May 31, 2025, and winding down Aserto as a commercial entity, stating that despite building what they believed was one of the best authorization platforms available, the economics of the hybrid SaaS business model did not work out to a sustainable business. Importantly, the open-source Topaz authorizer itself was not discontinued: the founders said a set of maintainers would continue supporting Topaz going forward, with the project remaining available at topaz.sh for teams that want to self-host an OPA-based authorization layer. As a result, anyone researching Aserto in 2026 should understand it primarily as a discontinued commercial product whose open-source core, Topaz, lives on independently; it is a useful case study and reference architecture for policy-as-code authorization, and its concepts and open-source tooling remain relevant even though Aserto the company and its paid hosted plans are no longer active. Competitors and successors in the fine-grained authorization space include Oso, Permit.io, and cloud-native alternatives built directly on Open Policy Agent.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'daf48211-2666-4915-ade5-f918f2d8b847';

