-- ── AspireIQ ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$AspireIQ, now rebranded as Aspire, is an all-in-one influencer marketing platform that helps e-commerce brands discover, manage, and pay content creators for sponsored campaigns and user-generated content.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE($q$approx $2,000+/month (custom, typically billed annually)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$AspireIQ Review 2026: Influencer Marketing Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$AspireIQ (now Aspire) is an influencer marketing platform for e-commerce brands. See its features, custom pricing from about $2,000/month, pros, and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$AspireIQ is an all-in-one influencer marketing platform for e-commerce and direct-to-consumer brands, now operating under the shortened name Aspire following a rebrand. The company was founded in 2013 in San Francisco, California, originally as Revfluence, by a founding team most commonly cited as including Anand Kishore, Eric Lam, and Suhaas Prasad. In September 2018, Revfluence rebranded to AspireIQ as part of a strategic shift toward deeper creator relationship management rather than pure influencer discovery, and in early 2026 the company rebranded again to the shorter name Aspire, updating its visual identity and website while keeping its core product and customer base intact. Over its history AspireIQ raised a total of about 26.4 million dollars in venture funding across multiple rounds, including a Series A round in November 2019. The platform is built around a full workflow for influencer and creator marketing: discovering and vetting creators, managing outreach and relationships through a built-in CRM, briefing and running campaigns, automating gifting and product seeding, tracking affiliate and commission-based partnerships, licensing creator content for reuse in paid advertising, and reporting on campaign performance and ROI. AspireIQ has counted well-known direct-to-consumer and e-commerce brands among its customers, including Glossier, Coola, Bombas, Newell, and Ruggable, and states it serves more than 400 brands in total. Pricing is not publicly listed and is quoted on a custom basis; third-party sources commonly cite a starting cost of roughly 2,000 dollars per month, often under a mandatory annual contract, putting it firmly in the mid-market-to-enterprise pricing tier alongside comparable influencer marketing platforms such as Grin, Upfluence, Traackr, and CreatorIQ. This pricing model means AspireIQ is generally out of reach for very small businesses or solo creators-turned-marketers, but it offers a comprehensive feature set for marketing teams that need to run influencer and UGC programs at meaningful scale, particularly for content licensing and paid-ad reuse. Compared to lighter-weight or self-serve influencer marketing tools, AspireIQ's strengths are its end-to-end workflow depth, established enterprise customer base, and years of product iteration since 2013, while its main drawback for prospective buyers is the lack of transparent, published pricing and the annual commitment typically required to get started.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6';

