-- ── AstroMenace ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$AstroMenace is a free, open-source 3D scrolling space shooter developed by Russian indie studio Viewizard, featuring spaceship upgrades and weapon purchases across 13 levels, available on Windows, macOS, and Linux.$q$, short_description),
  pricing_model = COALESCE($q$free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Russia$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$AstroMenace Review 2026: Free Open Source Shooter$q$, seo_title),
  seo_meta_description = COALESCE($q$AstroMenace is a free, open-source 3D space scroll-shooter by Viewizard. See its gameplay, ship upgrades, platform support, and history for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$AstroMenace is a 3D scrolling space shooter created by independent Russian developer Mikhail Kurinnoi under the studio name Viewizard. Development began in 2006 as a beta project, and the game was first released in February 2007. Its original release model was as shareware for Windows, priced at $14.95, with a free downloadable trial version available and a donation-based release offered for Linux users. Gameplay centers on 13 levels in which players destroy enemy aliens, pirates, and meteorites to earn in-game currency and experience points, which can then be spent on a selection of 22 ship types, 19 weapons, and 20 ship upgrades, giving the game a light progression and customization layer on top of its core arcade shooting action. A significant turning point came in October 2007, when the C++ source code for version 1.2 was released under the GNU General Public License version 3 (GPLv3), making AstroMenace an open-source project. In 2016, the game's content assets were also re-released under a Creative Commons CC BY-SA 4.0 license, and in April 2018 additional artwork with source files, such as 3ds render files, was published under GPLv3 in a separate repository. This dual open-sourcing of both code and content means anyone can inspect, modify, and redistribute the game, and development has continued on GitHub under the viewizard organization, with active releases as recently as 2025. AstroMenace is available across Windows, macOS, and Linux, and is packaged for easy installation on Linux through channels like Flathub and SourceForge. It gained recognition within the open-source gaming community, notably being ranked number one on a 2011 list of 19 Awesome Open Source Games for Linux published by Unixmen.com. Unlike the SaaS and commercial software tools typically covered in a software directory, AstroMenace is not a business product: it has no company behind it beyond Viewizard as an individual developer's studio, no pricing tiers, and no commercial support offering. It is best understood and presented as a completely free, actively maintained, open-source indie video game, of interest primarily to fans of retro-style arcade space shooters, Linux gamers looking for quality native open-source titles, and hobbyist developers interested in studying an open, long-running 3D game codebase.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a5b8096a-5ef5-481d-b6e1-09b700f1cd7f';

