INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Animation timeline with onion skinning$q$, $q$A frame-by-frame timeline lets artists animate sprites while seeing ghosted previous and next frames for smooth motion.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Layer and frame management$q$, $q$Group, blend, and toggle layers independently per animation frame for complex, multi-part sprites.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Indexed color and palette tools$q$, $q$Built-in palette editing, sorting, and indexed-color modes suited to classic pixel-art color constraints.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Tilemap and tileset editor$q$, $q$Design game levels and tile-based assets directly inside Aseprite without switching tools.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Lua scripting API$q$, $q$Automate repetitive tasks, build custom exporters, or batch-process files with a built-in scripting engine.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Sprite sheet and texture export$q$, $q$Export animations directly to sprite sheets, GIFs, and formats used by engines like Unity, Godot, and GameMaker.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Cross-platform desktop app$q$, $q$Native builds for Windows, macOS, and Linux, distributed via the official site, Steam, and itch.io.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Inexpensive one-time cost compared to subscription-based design tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Purpose-built for pixel art and sprite animation workflows$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Actively maintained with frequent updates since 2001$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Source code publicly available on GitHub for transparency and self-compiling$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Strong adoption, tutorials, and community support within indie game development$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Pre-built binaries are not free; users must compile from source to avoid paying$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Learning curve for artists unfamiliar with pixel-art specific workflows$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Not designed for general illustration, vector graphics, or photo editing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$No official mobile app$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Performance can degrade on very large canvas sizes$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Is Aseprite free?$q$, $q$Not for pre-built binaries. Aseprite costs $19.99 as a one-time purchase, though technically skilled users can compile the publicly available source code themselves at no cost.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Is Aseprite open source?$q$, $q$Its source code is publicly hosted on GitHub under a source-available license, so anyone can view and modify it, but Igara Studio sells the official pre-built binaries.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$What platforms does Aseprite support?$q$, $q$Aseprite runs natively on Windows, macOS, and Linux, and is distributed through its official website, Steam, and itch.io.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Can I use Aseprite for commercial game projects?$q$, $q$Yes, artwork created in Aseprite can be used freely in commercial games and other commercial projects.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Does Aseprite support animation?$q$, $q$Yes, animation is a core feature, with a frame-based timeline, onion skinning, and export to sprite sheets and GIFs.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Is there a subscription fee?$q$, $q$No. Aseprite uses a single one-time purchase price rather than a recurring subscription.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Who makes Aseprite?$q$, $q$Aseprite is developed by Igara Studio S.A., an Argentina-based company founded by original creator David Capello.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Game sprite creation$q$, $q$Drawing and animating character, enemy, and item sprites for 2D games.$q$, $q$Indie and professional game developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Pixel art illustration$q$, $q$Creating standalone pixel-art pieces, icons, and animated GIFs.$q$, $q$Digital artists and hobbyists$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Tile-based level design$q$, $q$Building tilesets and level layouts for 2D games using the built-in tilemap editor.$q$, $q$2D game level designers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$Aseprite License$q$, $q$$19.99$q$, $q$one-time$q$, NULL, $q$["Full editor with all features","Free updates within the same major version","Steam key included when purchased via Steam","Available for Windows, macOS, and Linux"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$overview$q$, $q$What Is Aseprite$q$, 2, ARRAY[$q$Aseprite is a purpose-built pixel-art editor and 2D sprite animation tool. It began life in 2001 as ASE (Allegro Sprite Editor), created by Argentine developer David Capello, and was rebranded Aseprite in 2009 as the project matured into a full animation and pixel-art suite.$q$, $q$In 2016, Capello and his family formed Igara Studio S.A. in Santa Fe, Argentina, to publish and sell Aseprite commercially. The source code was moved to GitHub and made publicly viewable and modifiable under a custom, source-available license, while compiled binaries for Windows, macOS, and Linux remain a paid, one-time purchase.$q$, $q$Today Aseprite is one of the most widely used tools in the indie game development and pixel-art community, valued for its animation-first workflow, tilemap support, and scripting capabilities.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Aseprite centers on a frame-and-layer animation timeline with onion skinning, letting artists see previous and next frames while drawing to keep motion consistent. Layers can be grouped, blended, and toggled per frame for complex animated sprites.$q$, $q$The tool includes dedicated pixel-art conveniences such as indexed color palettes, palette editing and sorting, pixel-perfect line and shape tools, and a tilemap and tileset editor for building game levels directly inside the app.$q$, $q$A built-in Lua scripting API allows users to automate repetitive tasks, write custom exporters, or batch-process sprite sheets, and Aseprite can export directly to sprite sheets, GIFs, and formats consumable by common game engines.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a0e89dfe-75ab-4aea-a6da-0f0334f44020', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Aseprite is sold as a single one-time purchase, currently $19.99, available through the official website, Steam, and itch.io. There is no subscription tier and no recurring billing after purchase.$q$, $q$Because the source code is publicly available on GitHub, technically inclined users can compile Aseprite themselves free of charge, though this requires setting up a build environment and does not include official support or pre-built installers.$q$, $q$Occasional discounts appear during Steam sales, but the standard price has remained close to $20 for years, making it inexpensive relative to subscription-based creative software.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Multi-model authorization$q$, $q$Supported RBAC, ABAC, PBAC, and ReBAC access-control models within a single platform.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Topaz open-source authorizer$q$, $q$Core authorization engine built on Open Policy Agent, remaining open source after the company wound down.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Policy-as-code workflow$q$, $q$Authorization policies were managed as code with GitHub and GitLab integration for review and deployment.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Developer SDKs$q$, $q$Client libraries for common languages and frameworks to embed authorization checks in applications.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Decision logging and audit trails$q$, $q$Recorded authorization decisions for compliance and debugging, with retention varying by plan.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Identity provider integrations$q$, $q$Connected to Auth0, Okta, and Azure AD to tie authorization to existing identity systems.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Self-hosted or SaaS deployment$q$, $q$Offered both a hosted control plane (now discontinued) and self-hosted deployment options.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Purpose-built developer experience for authorization, not just authentication$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Built on the widely adopted, CNCF-backed Open Policy Agent standard$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Supported multiple access-control models in one unified platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Founded by experienced developer-tools executives with a strong technical pedigree$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$The core Topaz authorizer remains open source and available after the company closed$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Aserto the company shut down its commercial SaaS by May 31, 2025$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$No longer offers paid hosted infrastructure or vendor support$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Teams must self-host and self-support the open-source Topaz project going forward$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Any organization that relied on the hosted SaaS needed to migrate off the platform$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$No ongoing commercial roadmap now that the company has wound down$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$What was Aserto?$q$, $q$Aserto was a developer-focused authorization platform that let applications enforce fine-grained permissions using policy-as-code, built on Open Policy Agent.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Is Aserto still available?$q$, $q$The commercial company and its hosted SaaS shut down by May 31, 2025. Its open-source Topaz authorizer remains available and maintained.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$What happened to Aserto?$q$, $q$The founders announced in 2025 that they were winding down Aserto as a commercial entity because the hybrid SaaS model was not economically sustainable.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$What is Topaz?$q$, $q$Topaz is Aserto's open-source authorizer built on Open Policy Agent. It continues to be developed and maintained independently at topaz.sh.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Was Aserto free to use?$q$, $q$Aserto historically offered a free Starter tier for personal projects, alongside paid Essentials, Pro, and Enterprise tiers, before all commercial plans were discontinued.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Who founded Aserto?$q$, $q$Aserto was founded in 2020 by Omri Gazitt and Gert Drapers, both experienced developer-tools executives.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Is Aserto open source?$q$, $q$The commercial Aserto product is discontinued, but its core Topaz authorizer remains open source under community maintenance.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$SaaS application permissions (historical)$q$, $q$Aserto let SaaS teams add fine-grained permissions and RBAC to customer-facing applications.$q$, $q$SaaS application developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Internal authorization control plane (historical)$q$, $q$Enterprises used Aserto to centralize authorization across multiple internal applications.$q$, $q$Enterprise platform and security teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$Self-hosted OPA-based authorization today$q$, $q$Teams can self-host the open-source Topaz authorizer for policy-based access control without relying on Aserto's discontinued SaaS.$q$, $q$Developers needing OPA-based authorization$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$overview$q$, $q$What Was Aserto$q$, 2, ARRAY[$q$Aserto was a Redmond, Washington-based startup founded in 2020 by developer-tools veterans Omri Gazitt and Gert Drapers, who set out to build a modern authorization platform for the age of SaaS and cloud applications.$q$, $q$The company raised a $5.1 million seed round in 2021 led by Costanoa Ventures, with backing from notable angel investors from Snowflake, Netlify, and GitHub, and built a platform that let developers add fine-grained, policy-based permissions to their applications.$q$, $q$In 2025 the founders announced they were shutting down Aserto's commercial SaaS control plane and winding down the company, citing an unsustainable business model, while committing that the open-source Topaz authorizer at the heart of the product would continue to be maintained.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Aserto supported multiple authorization models in a single platform, including role-based (RBAC), attribute-based (ABAC), policy-based (PBAC), and relationship-based (ReBAC) access control, so teams did not need separate tools for each model.$q$, $q$Its authorization decisions were powered by Topaz, an open-source authorizer built on Open Policy Agent, giving developers a battle-tested policy engine rather than a proprietary black box.$q$, $q$The platform offered policy-as-code workflows integrated with GitHub and GitLab, SDKs for common languages, identity provider integrations such as Auth0, Okta, and Azure AD, and decision logging for auditing access decisions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('daf48211-2666-4915-ade5-f918f2d8b847', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Historically, Aserto offered a free Starter tier for personal projects and evaluation, an Essentials tier at $0.20 per user per month, and custom-quoted Pro and Enterprise tiers for larger organizations.$q$, $q$As of 2025, Aserto no longer sells any commercial plans: the company wound down its hosted SaaS and paid support offerings entirely.$q$, $q$The only way to use Aserto's technology today is to self-host the open-source Topaz authorizer, which remains free and community-maintained at topaz.sh.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Single sign-on and social login$q$, $q$Lets end users log in once across applications or via existing social identity providers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Multi-factor and adaptive authentication$q$, $q$Adds configurable MFA and risk-based authentication flows to protect user accounts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Self-service registration and recovery$q$, $q$Pre-built flows for sign-up, login, password reset, and account recovery.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$B2B multi-tenant organizations$q$, $q$Supports separate, isolated identity spaces for each customer organization in a B2B SaaS product.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Developer SDKs and APIs$q$, $q$Pre-built libraries for popular frameworks to integrate authentication quickly.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Custom branding$q$, $q$Configurable login and registration screens to match a product's branding.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Built on WSO2 Identity Server$q$, $q$Inherits enterprise protocol support and scalability from WSO2's mature identity server codebase.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Backed by WSO2, a two-decade-old identity and API management vendor$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Generous free tier lets developers get started without upfront cost$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Positioned and priced as a lower-cost alternative to Auth0 with comparable core features$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Built on a proven, enterprise-grade identity server codebase$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Flexible MAU-based pricing that scales with actual usage$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Smaller community and partner ecosystem than larger CIAM vendors like Auth0 or Okta$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Enterprise pricing requires a custom sales conversation through the Trailblazer program$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Newer as a dedicated managed cloud product, having launched in 2021$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Documentation and third-party tutorials are less extensive for niche use cases$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Company ownership changed after EQT's 2024 acquisition of WSO2, which may affect long-term roadmap$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$What is Asgardeo?$q$, $q$Asgardeo is WSO2's cloud-hosted Customer Identity and Access Management (CIAM) platform for adding login, SSO, and user management to applications.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Who makes Asgardeo?$q$, $q$Asgardeo is made by WSO2, an enterprise integration, API management, and identity company founded in 2005 in Sri Lanka.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Is Asgardeo free?$q$, $q$Yes, Asgardeo has a free tier with a monthly active user allowance, with paid plans priced per MAU as usage grows.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$How is Asgardeo priced?$q$, $q$Asgardeo is priced per monthly active user (MAU), with the exact cost depending on billing cycle, business use case, and support plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$How does Asgardeo compare to Auth0?$q$, $q$WSO2 positions Asgardeo as offering comparable or broader core CIAM features than Auth0 at a lower cost, especially at higher MAU volumes.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Is Asgardeo built on open source?$q$, $q$Asgardeo is built on WSO2's Identity Server technology, which has open-source roots, though Asgardeo itself is delivered as a managed SaaS.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Does Asgardeo support B2B organizations?$q$, $q$Yes, Asgardeo supports multi-tenant B2B organization structures for SaaS companies serving multiple customer accounts.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Who owns WSO2?$q$, $q$WSO2 was acquired by EQT's Asian private capital fund in a deal valued at over $600 million, completed in 2024.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Adding login and SSO to a customer-facing app$q$, $q$Developers integrate Asgardeo's APIs and SDKs to add authentication without building identity infrastructure.$q$, $q$Application developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$B2B SaaS multi-tenant identity$q$, $q$SaaS product teams use Asgardeo's organization support to isolate identity per customer.$q$, $q$SaaS product and engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Enterprise CIAM migration$q$, $q$Enterprises migrate from legacy or on-premises identity systems to a managed cloud CIAM platform.$q$, $q$Enterprise IT and security teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Free MAU allowance","Core authentication and SSO","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Paid tiers$q$, $q$Custom, billed per monthly active user$q$, $q$monthly or annual$q$, NULL, $q$["Higher MAU limits","Additional business use cases","Standard support plans"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$Enterprise (Trailblazer)$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Custom MAU volume","Dedicated support","Advanced enterprise capabilities"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$overview$q$, $q$What Is Asgardeo$q$, 2, ARRAY[$q$Asgardeo is WSO2's cloud-hosted Customer Identity and Access Management (CIAM) platform, giving developers a managed way to add authentication, single sign-on, and user management to their applications without operating identity infrastructure themselves.$q$, $q$WSO2, the company behind Asgardeo, was founded in 2005 in Colombo, Sri Lanka, by Sanjiva Weerawarana, Paul Fremantle, and Davanum Srinivas, and built a long track record in enterprise integration, API management, and identity software before launching Asgardeo as a dedicated SaaS CIAM product in 2021.$q$, $q$In 2024, WSO2 was acquired by EQT's Asian private capital fund in a deal valued at over $600 million, providing continued investment behind its identity and API management product lines, including Asgardeo.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Asgardeo provides single sign-on, social login, and multi-factor and adaptive authentication out of the box, along with self-service registration, login, and account-recovery flows that developers can embed via SDKs and APIs.$q$, $q$It supports B2B multi-tenant organization structures, letting SaaS companies manage separate identity spaces for each customer organization, and allows custom branding of login and registration screens to match a product's look and feel.$q$, $q$Because it is built on WSO2's long-standing Identity Server codebase, Asgardeo inherits enterprise-grade protocol support (OAuth2, OpenID Connect, SAML) and scalability proven in on-premises deployments.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4b3800ea-87aa-41a1-a18e-912e02481106', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Asgardeo starts with a free tier that includes a monthly active user (MAU) allowance, letting developers sign up and start integrating authentication immediately.$q$, $q$Paid subscription tiers are priced per MAU and vary based on the selected business use case, billing cycle, and support plan, chosen through Asgardeo's subscription and billing portal.$q$, $q$Large enterprises can pursue custom pricing through WSO2's Trailblazer program, which tailors plans to specific MAU volume, support, and deployment requirements.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Ask.com question and answer search platform$q$, $q$The company's flagship destination, answering everyday user questions through search-style content.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Diversified content portfolio$q$, $q$Additional owned-and-operated sites spanning health, home, shopping, government resources, and finance topics.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$SEO-driven content strategy$q$, $q$Content built around search demand to attract large volumes of organic search traffic.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Performance marketing and ad monetization$q$, $q$Revenue generated through programmatic and performance-based advertising rather than subscriptions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Large-scale audience reach$q$, $q$The company reports reaching over 200 million people per month across its network.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Backing of parent company IAC$q$, $q$Operates as part of IAC, a large, publicly traded media and internet holding company.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Long-established, widely recognized consumer brand with decades of history$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Very large monthly audience reach across its portfolio of sites$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Backed by IAC, a large and stable public media holding company$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Diversified portfolio of content brands reduces reliance on any single site or topic$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Deep, long-standing expertise in SEO-driven and answer-style content$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Not a software product or tool; there is no subscription or self-serve pricing to evaluate$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Revenue depends heavily on the health of the digital advertising market$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Some legacy brand recognition is still tied to the earlier Ask Jeeves identity$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Limited public disclosure of site-level traffic and financial performance$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Question-and-answer-style content sites face growing pressure from AI-generated search answers changing how people search$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$What is Ask Media Group?$q$, $q$Ask Media Group is a digital media and content publishing company owned by IAC that operates Ask.com and a portfolio of other content websites.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Is Ask Media Group the same as Ask.com?$q$, $q$Ask.com is Ask Media Group's flagship brand and best-known property, but the company also operates several other content websites.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Who owns Ask Media Group?$q$, $q$Ask Media Group is owned and operated by IAC, a publicly traded media and internet holding company.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$How does Ask Media Group make money?$q$, $q$It generates revenue primarily through advertising and performance marketing on its content network, not through subscriptions or software fees.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$What other websites does Ask Media Group operate?$q$, $q$Its portfolio has included sites such as SymptomFind, Pronto, Simpli, GovtSearches.com, Ideal Home and Garden, and CanDoFinance, alongside Ask.com.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$When was Ask Media Group founded?$q$, $q$Its roots go back to 1996, when Ask Jeeves was founded; the company was later acquired by IAC in 2005 and evolved into today's Ask Media Group.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Does Ask Media Group have pricing plans?$q$, $q$No, it is not a purchasable software product. It is an ad-supported media business with no subscription plans for consumers.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Answering everyday search queries$q$, $q$Consumers use Ask.com and related sites to find quick answers to common questions.$q$, $q$General consumers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Large-scale advertising and media buying$q$, $q$Brands and advertisers use Ask Media Group's content network to reach a large, engaged audience.$q$, $q$Advertisers and media buyers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$Content partnerships and licensing$q$, $q$Publishers and content partners work with Ask Media Group's network for distribution and monetization.$q$, $q$Publishers and content partners$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$overview$q$, $q$What Is Ask Media Group$q$, 2, ARRAY[$q$Ask Media Group is a digital media and content publishing company owned by IAC, best known for operating Ask.com. It is not a software-as-a-service product, and it does not sell subscriptions, seats, or API usage; it is a media business that monetizes content through advertising.$q$, $q$The company's history dates to 1996, when Ask Jeeves was founded in Berkeley, California, by Garrett Gruener and David Warthen. IAC acquired Ask Jeeves in 2005 for roughly 1.85 billion dollars, and the brand transitioned to Ask.com and later to the Ask Media Group name as its owned-and-operated portfolio expanded beyond a single search site.$q$, $q$Headquartered in Oakland, California, Ask Media Group now runs a network of content brands spanning topics like health, home, shopping, government resources, and personal finance, in addition to its flagship Ask.com property.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$key-features$q$, $q$What Ask Media Group Does$q$, 2, ARRAY[$q$Rather than product features, Ask Media Group is best described by its operating capabilities: a large-scale, SEO-driven question-and-answer and informational content network anchored by Ask.com, reaching over 200 million people monthly according to the company.$q$, $q$It operates a diversified portfolio of niche content brands beyond Ask.com, spanning health, home and garden, shopping, government information, and personal finance topics, reducing reliance on any single site.$q$, $q$Its business relies on data science and performance marketing technology to monetize this audience through programmatic advertising, rather than through subscriptions or licensing fees.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('57a97ac4-376f-4dca-b06f-6fa8252794f0', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Ask Media Group does not have a pricing page, plan tiers, or a subscription product for end users, because it is a media company rather than a software tool.$q$, $q$Consumers use its sites like Ask.com for free; the company generates revenue from advertisers and programmatic ad partners rather than from user payments.$q$, $q$Businesses interested in working with Ask Media Group typically engage through advertising, media buys, or content partnerships rather than purchasing a software plan.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$Peer-to-peer library synchronization$q$, $q$Keeps a photo library consistent across devices without routing files through cloud storage.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$Unified collections system$q$, $q$Combines albums, tags, color labels, ratings, and folders into a single organizational concept.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$File system mirrored organization$q$, $q$Changes made directly in the operating system's file browser are recognized and reflected in Aspect.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$Local-first performance$q$, $q$Designed to stay fast even with large photo libraries by avoiding cloud round-trips.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$Privacy-focused architecture$q$, $q$Bildhuus states no user data leaves the user's own devices under the peer-to-peer sync model.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$One-time AspectPro license$q$, $q$Unlocks multi-device sync as a one-time purchase rather than a recurring subscription.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$No mandatory subscription; AspectPro is a one-time purchase$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$True local-first, privacy-respecting architecture with no cloud storage dependency$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$File system stays in sync with the app's own organization, reducing vendor lock-in$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$Self-funded, independent company not driven by investor growth pressure$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$Early-bird pricing offers meaningful savings ahead of the planned final release$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$Product is still in a pre-final-release, early-bird pricing phase as of 2026$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$Peer-to-peer sync requires devices to be reachable, unlike always-on cloud sync$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$Smaller company and community compared to established DAM tools like Lightroom or Capture One$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$Limited independent, long-term reviews given the product's early stage$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$Founding year and company size details are not publicly documented in detail$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$What is Aspect?$q$, $q$Aspect is a desktop digital asset manager for photographers, made by Bildhuus, that organizes photo libraries using a collections system and keeps them in sync across devices without cloud storage.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$Does Aspect require a subscription?$q$, $q$No. AspectPro is sold as a one-time license rather than a recurring subscription, and a free tier is also available.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$Does Aspect sync photos to the cloud?$q$, $q$No, Aspect uses peer-to-peer synchronization directly between a user's own devices instead of cloud storage.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$Who makes Aspect?$q$, $q$Aspect is made by Bildhuus GmbH, a software company based in Lubeck, Germany.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$Is there a free version of Aspect?$q$, $q$Yes, Aspect offers a free version with core library organization features, alongside the paid AspectPro license.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$How much does AspectPro cost?$q$, $q$AspectPro is currently priced at EUR 129 during its early-bird period, planned to rise toward EUR 189 at final release.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$Organizing a photo library across multiple devices$q$, $q$Photographers keep their library synced across a desktop and laptop using peer-to-peer sync.$q$, $q$Photographers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$Managing photos without cloud storage$q$, $q$Privacy-conscious users organize large photo libraries without uploading images to third-party servers.$q$, $q$Privacy-conscious users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$Replacing folder-based photo organization$q$, $q$Users replace ad-hoc folder structures with a searchable, tag-and-collection-based system.$q$, $q$Hobbyist and semi-professional photographers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$Free$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Core library organization","Collections (albums, tags, ratings)","File-system mirrored organization"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$AspectPro (early-bird)$q$, $q$EUR 129$q$, $q$one-time$q$, NULL, $q$["All free features","Peer-to-peer multi-device sync","One year of upgrades included","Early-bird pricing before final release"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$overview$q$, $q$What Is Aspect$q$, 2, ARRAY[$q$Aspect is a digital asset manager built for photographers by Bildhuus GmbH, a software company based in Lubeck, Germany. It is designed to organize and keep photo libraries in sync across multiple devices using peer-to-peer synchronization rather than a cloud-based backend.$q$, $q$Bildhuus states that it has developed Aspect in a fully self-funded way, positioning the product's independence from outside investors as a deliberate choice to keep the roadmap focused on users rather than growth targets.$q$, $q$As of its early-bird pricing period, Aspect is approaching a final release targeted for mid-2026, with a free tier and a paid AspectPro license already available.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Aspect organizes photos through a unified concept called collections, which combines the functions of albums, tags, color labels, star ratings, and folder hierarchies into a single, fast interface.$q$, $q$Its file system integration mirrors the app's organization to the actual files on disk, so changes made outside Aspect, such as moving or renaming files in Finder or Explorer, are recognized and reflected inside the app.$q$, $q$Rather than syncing through the cloud, Aspect uses peer-to-peer technology to keep libraries consistent across a user's own devices, which the company frames as both a privacy benefit and a way to avoid ongoing cloud storage costs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7b930705-cfc0-4768-aaaa-2e63acbd6095', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Aspect offers a free version covering core library organization and collections, alongside a paid AspectPro license that unlocks peer-to-peer multi-device synchronization.$q$, $q$AspectPro is sold as a one-time purchase rather than a subscription. During its current early-bird period, it is priced at EUR 129, roughly 31 percent below its planned post-launch price of EUR 189, and includes one year of software upgrades.$q$, $q$Bildhuus has stated that the early-bird price will increase gradually each month as the product approaches its final release.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Creator discovery and relationship CRM$q$, $q$Find, vet, and organize relationships with content creators in a centralized database.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Campaign briefing and workflow management$q$, $q$Plan, brief, and manage influencer campaigns from a single workflow.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Automated payments and product seeding$q$, $q$Streamline paying creators and sending gifted products at scale.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Content and usage-rights licensing$q$, $q$License creator-generated content for reuse in paid advertising and other marketing channels.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Affiliate and commission tracking$q$, $q$Track performance-based creator partnerships and commission payouts.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Campaign performance and ROI reporting$q$, $q$Measure the impact of influencer campaigns with built-in analytics.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$E-commerce platform integrations$q$, $q$Connects with platforms such as Shopify to tie campaign activity to sales data.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Comprehensive end-to-end workflow from creator discovery to payment and licensing$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Established reputation with well-known direct-to-consumer and e-commerce brand customers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Strong focus on user-generated content licensing, valuable for reuse in paid ads$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Backed by meaningful venture funding and over a decade of product development$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Dedicated account support typically included for enterprise customers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Pricing is not public and requires a sales conversation to obtain a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$High entry cost, commonly cited around $2,000 per month, limits access for small businesses$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Typically requires an annual contract commitment$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Smaller brands may find lighter-weight, self-serve tools more cost effective$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$The breadth of features can mean a steeper onboarding and learning curve$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$What is AspireIQ?$q$, $q$AspireIQ is an all-in-one influencer marketing platform that helps e-commerce brands find, manage, and pay content creators for campaigns and user-generated content.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Is AspireIQ the same as Aspire?$q$, $q$Yes, AspireIQ rebranded to the shorter name Aspire in 2026, keeping the same core product and customer base.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$How much does AspireIQ cost?$q$, $q$Pricing is custom, with third-party sources commonly citing a starting cost of roughly $2,000 per month under an annual contract.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Does AspireIQ offer a free trial?$q$, $q$No free trial or self-serve tier is publicly advertised; prospective customers need to contact sales for a demo and quote.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Who are AspireIQ's competitors?$q$, $q$Comparable influencer marketing platforms include Grin, Upfluence, Traackr, and CreatorIQ.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$What brands use AspireIQ?$q$, $q$AspireIQ has counted brands such as Glossier, Coola, Bombas, Newell, and Ruggable among its customers.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$When was AspireIQ founded?$q$, $q$It was founded in San Francisco in 2013 as Revfluence, before rebranding to AspireIQ in 2018 and then Aspire in 2026.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Influencer seeding and gifting campaigns$q$, $q$Brands manage product seeding and gifting programs to generate organic creator content.$q$, $q$E-commerce and direct-to-consumer brands$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Affiliate and commission-based creator partnerships$q$, $q$Marketing teams track and pay creators through performance-based commission structures.$q$, $q$Marketing and growth teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Licensing creator content for paid ads$q$, $q$Performance marketing teams license user-generated content for reuse in paid advertising campaigns.$q$, $q$Performance marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$Custom / Enterprise$q$, $q$Custom, starting around $2,000/month$q$, $q$annual$q$, NULL, $q$["Creator discovery and CRM","Campaign management","Payments and product seeding","Content licensing","Reporting and analytics"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$overview$q$, $q$What Is AspireIQ$q$, 2, ARRAY[$q$AspireIQ, now rebranded as Aspire, is an influencer and creator marketing platform for e-commerce and direct-to-consumer brands, covering the full workflow from creator discovery through payment and content licensing.$q$, $q$The company was founded in San Francisco in 2013 as Revfluence, rebranded to AspireIQ in 2018 as it shifted focus toward creator relationship management, and rebranded again to the shorter name Aspire in 2026.$q$, $q$Over its history, the company raised roughly 26.4 million dollars in venture funding, including a Series A round in 2019, and built a customer base that includes well-known brands like Glossier, Coola, Bombas, and Ruggable.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$AspireIQ combines creator discovery and a relationship CRM with campaign briefing and workflow management, letting marketing teams find, vet, and organize creator partnerships in one place.$q$, $q$The platform automates influencer payments, gifting, and product seeding, and supports affiliate and commission-based partnership tracking for performance-driven creator programs.$q$, $q$It also offers content and usage-rights licensing so brands can legally reuse creator-generated content in paid advertising, alongside campaign performance and ROI reporting, with integrations into e-commerce platforms like Shopify.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b3d4c4d0-2012-458a-bb3e-5c9e61d0a7d6', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$AspireIQ does not publish pricing and instead quotes custom plans based on a brand's needs, typically requiring a sales conversation to get an exact quote.$q$, $q$Third-party sources commonly cite a starting cost of roughly 2,000 dollars per month, usually under an annual contract, positioning AspireIQ in the mid-market-to-enterprise segment of influencer marketing software.$q$, $q$This pricing approach is similar to competitors like Grin and Upfluence, most of which also require custom quotes rather than offering self-serve, published plans.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$No-code assertion builder$q$, $q$Define expected API response behavior using built-in patterns without writing test scripts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Scheduled uptime and synthetic monitoring$q$, $q$Continuously checks production services for availability and correctness on a set schedule.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$GitHub-triggered test runs$q$, $q$Automatically execute tests when code is pushed or deployed, integrating with CI/CD pipelines.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Slack and email alerting$q$, $q$Sends failure notifications to Slack channels or email so teams can respond quickly.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Multi-step functional test cases$q$, $q$Chain multiple requests together to test realistic, multi-step API workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Team collaboration$q$, $q$Share services and test results across team members, with limits scaling by plan.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Historical result retention$q$, $q$Stores past test and monitoring results for auditing and debugging, with retention limits by plan.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$No-code approach makes it accessible to QA staff without deep coding experience$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Flat per-account pricing rather than per-user fees keeps costs predictable for small teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Generous free Personal plan for individuals and small projects$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Direct GitHub integration streamlines automated testing on every deploy$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Simple, transparent, publicly published pricing tiers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Feature set is narrower than large, general-purpose API platforms like Postman$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Entry-level paid tiers have modest service and test limits that active teams may outgrow quickly$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Smaller company with a narrower third-party integration ecosystem$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$No advertised support for advanced load or performance testing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Team seat limits are capped even on the highest published tier$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$What is Assertible?$q$, $q$Assertible is a no-code API and web service testing and monitoring tool that lets teams validate API responses and monitor uptime without writing test scripts.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Is Assertible free?$q$, $q$Yes, Assertible offers a free Personal plan, with paid plans starting at $25 per month for more services, tests, and team members.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Does Assertible require coding?$q$, $q$No, Assertible uses a no-code assertion builder, though it also supports more advanced, multi-step functional test cases.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Does Assertible integrate with GitHub?$q$, $q$Yes, Assertible can automatically trigger test runs when code is pushed to GitHub.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$How many services can I monitor for free?$q$, $q$The free Personal plan supports up to 2 web services with 10 tests per service.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Who founded Assertible?$q$, $q$Assertible was founded in 2015 by Christopher Reichert and Cody Reichert.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Automated API regression testing in CI/CD$q$, $q$Development and QA teams run automated assertion checks against APIs on every deploy.$q$, $q$Backend developers and QA engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Uptime and synthetic monitoring for production APIs$q$, $q$DevOps teams schedule ongoing checks to catch outages and correctness issues in production.$q$, $q$DevOps and site reliability teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Non-technical QA testing without writing code$q$, $q$QA analysts build and run functional API tests using the no-code assertion builder.$q$, $q$QA analysts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Personal$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["2 web services","10 tests per service","1,000 result retention","1-2 team members"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Standard$q$, $q$$25$q$, $q$monthly$q$, NULL, $q$["25 web services","500 tests per service","5,000 result retention","1 team member","1 month free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Startup$q$, $q$$50$q$, $q$monthly$q$, NULL, $q$["25 web services","500 tests per service","5,000 result retention","up to 10 team members","1 month free trial"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$Business$q$, $q$$100$q$, $q$monthly$q$, NULL, $q$["50 web services","1,000 tests per service","10,000 result retention","up to 20 team members","1 month free trial"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$overview$q$, $q$What Is Assertible$q$, 2, ARRAY[$q$Assertible is an API and web service testing and monitoring platform founded in 2015 by Christopher Reichert and Cody Reichert. It focuses on helping teams verify that their HTTP-based APIs and web services behave correctly and stay available.$q$, $q$Rather than requiring users to write test scripts, Assertible provides a no-code assertion builder for defining expected API behavior, alongside scheduled synthetic monitoring for uptime tracking.$q$, $q$The tool is designed to plug directly into existing development workflows, with GitHub-triggered test runs and Slack or email alerting when something fails.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Assertible's assertion builder lets users validate API response data, status codes, and headers using pre-built, industry-standard patterns without writing custom code, and supports chaining multiple requests into functional, multi-step test cases.$q$, $q$Scheduled synthetic monitoring continuously checks the uptime and correctness of production services, while GitHub integration allows tests to run automatically whenever code is deployed.$q$, $q$Teams can collaborate on shared services and results, with historical result retention that scales by plan for auditing and debugging past test runs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1a4b2be9-43e2-4d4d-8dc5-0d36c5f7848a', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Assertible offers a free Personal plan supporting up to 2 web services, 10 tests per service, and 1,000 stored results, suitable for individuals or small projects.$q$, $q$Paid plans are billed as a single flat monthly charge per account rather than per user: Standard at $25/month, Startup at $50/month, and Business at $100/month, each increasing the number of services, tests per service, result retention, and team member limits.$q$, $q$All paid plans include a one-month free trial, prorated billing when changing plans, and the ability to cancel at any time.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$3D scrolling shooter gameplay$q$, $q$Arcade-style 3D scroll-shooter action across 13 levels of enemies and obstacles.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$22 selectable ship types$q$, $q$A range of purchasable spacecraft with different stats and playstyles.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$19 weapon types$q$, $q$Unlockable and equippable weapons for customizing combat approach.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$20 ship upgrade options$q$, $q$Additional upgrades purchasable with in-game currency to strengthen ships between missions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$Currency and experience progression$q$, $q$Earn in-game currency and experience by destroying enemies, spent on ships, weapons, and upgrades.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$Cross-platform availability$q$, $q$Native support for Windows, macOS, and Linux, with Flathub and SourceForge packaging.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$Completely free to download and play$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$Fully open-source, with both code (GPLv3) and content (CC BY-SA 4.0) freely licensed$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$Long-running, actively maintained project with nearly two decades of history$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$Recognized within Linux and open-source gaming communities as a standout free title$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$Available natively across Windows, macOS, and Linux$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$Graphics and design feel dated compared to modern commercial space shooters$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$Single-player only, with no multiplayer or online modes$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$Small, hobbyist-scale development team means slower feature updates$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$Limited marketing and visibility compared to mainstream indie games$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$Interface and controls may feel dated to players used to modern titles$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$What is AstroMenace?$q$, $q$AstroMenace is a free, open-source 3D scrolling space shooter developed by Russian indie studio Viewizard.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$Is AstroMenace free?$q$, $q$Yes, AstroMenace is completely free and open source, though it was originally sold as paid shareware before its 2007 open-source release.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$What platforms does AstroMenace support?$q$, $q$AstroMenace runs on Windows, macOS, and Linux, with easy installation on Linux via Flathub and SourceForge.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$Who developed AstroMenace?$q$, $q$AstroMenace was developed by Viewizard, the studio name of independent Russian developer Mikhail Kurinnoi.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$Is AstroMenace still being updated?$q$, $q$Yes, development continues on GitHub, with releases continuing into the mid-2020s.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$Was AstroMenace always free?$q$, $q$No, it originally launched in 2007 as paid Windows shareware before its source code was released under GPLv3 later that year.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$Casual arcade space-shooter gaming$q$, $q$Playing a free, retro-style 3D shooter for casual entertainment.$q$, $q$Retro and arcade game fans$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$Studying an open-source 3D game codebase$q$, $q$Reviewing AstroMenace's public source code to learn 3D game development techniques.$q$, $q$Hobbyist game developers and students$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$Native Linux gaming$q$, $q$Playing a free, natively packaged game on Linux without relying on compatibility layers.$q$, $q$Linux desktop users$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$overview$q$, $q$What Is AstroMenace$q$, 2, ARRAY[$q$AstroMenace is a 3D scrolling space shooter originally developed by independent Russian game creator Mikhail Kurinnoi under the studio name Viewizard, with beta development beginning in 2006 and the first release arriving in February 2007.$q$, $q$The game was initially sold as Windows shareware for $14.95, with a free trial version and a donation-based release for Linux, before its source code was released under the GPLv3 open-source license in October 2007.$q$, $q$Development has continued for nearly two decades, with the project's code and content assets hosted publicly on GitHub and active releases continuing into the mid-2020s.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$AstroMenace offers 13 levels of arcade-style 3D scrolling shooter gameplay, where players destroy aliens, pirates, and meteorites to earn currency and experience points.$q$, $q$Players can spend earned currency on a selection of 22 ship types, 19 weapons, and 20 ship upgrades, adding a progression and customization layer between missions.$q$, $q$The game is fully cross-platform, running natively on Windows, macOS, and Linux, with convenient packaging for Linux users through Flathub and SourceForge.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5b8096a-5ef5-481d-b6e1-09b700f1cd7f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$AstroMenace is completely free to download and play today, having transitioned from its original paid shareware model to a fully open-source release in 2007.$q$, $q$Both the game's source code (GPLv3) and its content assets (CC BY-SA 4.0) are freely licensed, so there is no purchase, subscription, or in-app payment required.$q$, $q$The game can be downloaded directly from its GitHub repository, SourceForge, or Flathub at no cost.$q$]::text[], 2);
